class TreeNode:
    def __init__(self, val=0, left=None, right=None):
        self.val = val
        self.left = left
        self.right = right

class Solution:
    def generateTrees(self, n: int) -> list[TreeNode]:
        if n == 0:
            return []

        memo = {}

        def _generate_trees_helper(start, end):
            if start > end:
                return [None]
            if (start, end) in memo:
                return memo[(start, end)]

            res = []
            for i in range(start, end + 1):
                left_subtrees = _generate_trees_helper(start, i - 1)
                right_subtrees = _generate_trees_helper(i + 1, end)

                for l_tree in left_subtrees:
                    for r_tree in right_subtrees:
                        root = TreeNode(i)
                        root.left = l_tree
                        root.right = r_tree
                        res.append(root)

            memo[(start, end)] = res
            return res

        return _generate_trees_helper(1, n)
